        substrings = []
        temp = s[0]  # Start with the first character

        for i in range(1, len(s)):
            if s[i] == s[i-1]:  # If the character is the same as the previous one
                temp += s[i]  # Add to the current substring
            else:
                substrings.append(temp)  # Store the substring
                temp = s[i]  # Start a new substring

        substrings.append(temp)  # Append the last substring
        for i in substrings:
            if len(i)==k:
                return True
        return False

