class Trie:
    def __init__(self):
        self.trie=TrieNode()
    def insert(self, word: str) -> None:
      cur=self.trie
      for i in word:
        if i not in cur.children:
          cur.children[i] = TrieNode()
        cur = cur.children[i]
      cur.is_end = True
    def search(self, word: str) -> bool:
      r=self.trie
      for c in word:
        if c not in r.children:
          return False
        r=r.children[c]
      return r.is_end
    def startsWith(self, prefix: str) -> bool:
      root=self.trie
      for j in prefix:
        if j not in root.children:
          return False
        root=root.children[j]
      return True

