class Solution:
    def validPath(self, n: int, edges: List[List[int]], source: int, destination: int) -> bool:
        graph = defaultdict(list)
        visited=set()
        maps=deque([source])
        for a, b in edges:
            graph[a].append(b)
            graph[b].append(a)
        while maps:
            node=maps.popleft()
            if node==destination:
                return True
            if node not in visited:
                visited.add(node)
            for i in graph[node]:
                if i not in visited:
                    maps.append(i)
        return False

