        result=[]
        count=0
        def backtrack(start, path):
            result.append(path[:])
            for i in range(start, len(nums)):
                path.append(nums[i])
                backtrack(i+1, path)
                path.pop()
        backtrack(0, [])
        for j in result:
            valid=True
            for x in j:
                for y in j:
