class Solution:
    def findTilt(self, root: Optional[TreeNode]) -> int:
        big=0
        def sumTree(root):
            if not root:
                return 0
            return root.val + sumTree(root.left) + sumTree(root.right)
        def recurse(root):
            nonlocal big
            summs=0
            if not root:
                return 0
            else:
                summs+=abs(sumTree(root.left)-sumTree(root.right))
                recurse(root.left)
                recurse(root.right)
            big+=summs
        recurse(root)
        return big

