class Solution:
    def averageOfSubtree(self, root: TreeNode) -> int:
        big=0
        def sumtree(root):
            if not root:
                return 0
            return root.val+sumtree(root.left)+sumtree(root.right)
        def countnodes(root):
            if not root:
                return 0
            return 1 + countnodes(root.left) + countnodes(root.right)
        def dfs(root):
            nonlocal big
            if not root:
                return 0
            else:
                if int(sumtree(root)/countnodes(root))==root.val:
                    big+=1
            dfs(root.right)
            dfs(root.left)
        dfs(root)
        return big

