class Solution:
    def isCousins(self, root: Optional[TreeNode], x: int, y: int) -> bool:
        lst={}
        def dfs(root, x, y, depth):
            if not root:
                return []
            if root.right:
                if root.right.val==x:
                    if x not in lst:
                        lst[x]=[]
                    lst[x].append(root.val) 
                    lst[x].append(depth)
                if root.right.val==y:
                    if y not in lst:
                        lst[y]=[]
                    lst[y].append(root.val) 
                    lst[y].append(depth)
            if root.left:
                if root.left.val==x:
                    if x not in lst:
                        lst[x]=[]
                    lst[x].append(root.val) 
                    lst[x].append(depth)
                if root.left.val==y:
                    if y not in lst:
                        lst[y]=[]
                    lst[y].append(root.val) 
                    lst[y].append(depth)
            dfs(root.right, x, y, depth+1)
            dfs(root.left, x, y, depth+1)
        dfs(root, x, y, 0)
        if x in lst and y in lst:
            return lst[x][1]==lst[y][1] and lst[x][0]!=lst[y][0]
        return False

