        while n>1:
            newNums=[0]*(n//2)
            for i in range(0, n//2):
                if i%2==0:
                    newNums[i]=min(nums[2*i], nums[2*i+1])
                else:
                    newNums[i]=max(nums[2*i], nums[2*i+1])
            n//=2
            nums=newNums
        return nums[-1]

