class Solution:
    def sumEvenGrandparent(self, root: Optional[TreeNode]) -> int:
        ans=0
        def dfs(root):
            nonlocal ans
            if not root:
                return []
            if root.val%2==0:
                if root.right:
                    if root.right.right:
                        ans+=root.right.right.val
                    if root.right.left:
                        ans+=root.right.left.val
                if root.left:
                    if root.left.left:
                        ans+=root.left.left.val
                    if root.left.right:
                        ans+=root.left.right.val
            dfs(root.right)
            dfs(root.left)
        dfs(root)
        return ans

