                if nums[i]>nums[i-k] and nums[i]>nums[i+k]:
                    count+=nums[i]
            elif i-k<0 and i+k>=len(nums):
                count+=nums[i]
            else:
                if i-k>=0 and i+k>=len(nums):
                    if nums[i-k]<nums[i]:
