class Solution:
    def zigzagLevelOrder(self, root: Optional[TreeNode]) -> List[List[int]]:
        ans=dict()
        lst=[]
        def dfs(root, depth):
            if not root:
                return 
            if depth not in ans:
                ans[depth]=[]
            ans[depth].append(root.val)
            dfs(root.left, depth+1)
            dfs(root.right, depth+1)
        dfs(root, 0)
        for i in range(len(list(ans.values()))):
            if i%2==0:
                lst.append(list(ans.values())[i])
            else:
                lst.append(list(ans.values())[i][::-1])
        return lst

