class Solution:
    def isEvenOddTree(self, root: Optional[TreeNode]) -> bool:
        import numpy as np
        ans=dict()
        counter=0
        def dfs(root, depth):
            if not root:
                return 
            if depth not in ans:
                ans[depth]=[]
            ans[depth].append(root.val)
            dfs(root.left, depth+1)
            dfs(root.right, depth+1)
        dfs(root, 0)
        for idx, val in enumerate(list(ans.values())):
            if idx%2==0:
                if all(i%2==1 for i in val) and np.all(np.diff(val)>0):
                    counter+=1
            elif idx%2==1:
                if all(i%2==0 for i in val) and np.all(np.diff(val)<0):
                    counter+=1
        return counter==len(ans.values())

