        lst=[]
        for index, word in enumerate(sentence.split()):
            if word[0] in 'aeiouAEIOU':
                word+='ma'
            elif word[0] in "bcdfghjklmnpqrstvwxyzBCDFGHJKLMNPQRSTVWXYZ":
                temp=word[0]
                word=word[1:]
                word+=temp
                word+='ma'
            for i in range(index+1):
                word+='a'
            lst.append(word)
        return " ".join(lst)

