class Solution:
    def smallestRangeI(self, nums: List[int], k: int) -> int:
        maximum=max(nums)
        minimum=min(nums)
        for _ in range(k):
            maximum-=1
            minimum+=1
            if minimum>=maximum:
                return 0
        return maximum-minimum

