class Solution:
    def semiOrderedPermutation(self, nums: List[int]) -> int:
        x=-1
        y=-1
        n=len(nums)
        for i, j in enumerate(nums):
            if j==1:
                x=i
            elif j==n:
                y=i
        if x<y:
            return x + (n-y-1)
        return  x + (n-y-1) - 1

