class Solution:
    def oddString(self, words: List[str]) -> str:
        ans = {}
        for idx, word in enumerate(words):
            lst = []
            for j in range(len(word) - 1):
                lst.append(ord(word[j + 1]) - ord(word[j]))
            ans[idx] = lst  # use index as key to avoid overwriting
        values = list(ans.values())
        for k in ans:
            if values.count(ans[k]) == 1:
                return words[k]  # return the word at that index

