class Solution:
    def nearestValidPoint(self, x: int, y: int, points: List[List[int]]) -> int:
        index = float('inf')
        value = float('inf')
        for i in range(len(points)):
            if (x == points[i][0] or y == points[i][1]) and abs(points[i][0] - x) + abs(points[i][1] - y) < value:
                value = abs(points[i][0] - x) + abs(points[i][1] - y)
                index = i
        return index if index != float('inf') else -1

