class Solution:
    def hardestWorker(self, n: int, logs: List[List[int]]) -> int:
        hashmap = dict()
        lst = []
        prev = 0
        for id, leave in logs:
            if id not in hashmap:
                hashmap[id] = []
            hashmap[id].append(leave - prev)
            prev = leave

        maximum = max(max(v) for v in hashmap.values())
        for k, v in hashmap.items():
            if max(v) == maximum:
                lst.append(k)
        return min(lst)

