class Solution:
    def isPathCrossing(self, moves: str) -> bool:
        seen={(0, 0)}
        ans=[0, 0]
        for i in moves:
            if i=='N':
                ans[-1]=ans[-1]+1
            elif i=='S':
                ans[-1]=ans[-1]-1
            elif i=='W':
                ans[0]=ans[0]+1
            elif i=='E':
                ans[0]=ans[0]-1
            pos=(ans[0], ans[-1])
            if pos in seen:
                return True
            seen.add(pos)
        return False

