class Solution:
    def constructTransformedArray(self, nums: List[int]) -> List[int]:
        n=len(nums)
        result=[0]*n
        for i in range(n):
            if nums[i]>0:
                result[i]=nums[(i+nums[i])%n]
            elif nums[i]<0:
                result[i]=nums[(i-abs(nums[i])+n)%n]
            else:
                result[i]=nums[i]
        return result

class Solution:
    def reorderSpaces(self, text: str) -> str:
        spaces=0
        words=len(text.split())
        s=''
        for i in text:
            if i==' ':
                spaces+=1
        if words == 1:
            return text.split()[0] + ' ' * spaces
        ans=divmod(spaces, words-1)
        for i in text.split():
            s+=i
            s+=' '*ans[0]
        return s.strip()+(' '*ans[-1])

