class Solution:
    def finalPositionOfSnake(self, x: int, commands: List[str]) -> int:
        i = 0
        j = 0
        for n in commands:
            if n == 'RIGHT':
                i += 1
            elif n == 'LEFT':
                i -= 1
            elif n == 'UP':
                j -= 1
            elif n == 'DOWN':
                j += 1
        return abs((j * x) + i)

