class Solution:
    def longestWord(self, words: List[str]) -> str:
        def prefixes(word):
            lst=[]
            for i in range(1, len(word)+1):
                lst.append(word[:i])
            return lst
        ans=[]
        for word in words:
            if all(i in words for i in prefixes(word)[:-1]):
                ans.append(word)
        return min(ans, key=lambda x: (-len(x), x)) if ans else ''

