        hm=list()
        ans=[]
        for x, y in points:
            hm.append([sqrt((x-0)**2+(y-0)**2), [x, y]])
        for i in sorted(hm, key=lambda x: x[0])[:k]:
            ans.append(i[-1])
        return ans

class Solution:
    def resultsArray(self, queries: List[List[int]], k: int) -> List[int]:
        heap=[]
        heapq.heapify(heap)
        ans=[]
        for x, y in queries:
            heapq.heappush(heap, -(abs(x)+abs(y)))
            if len(heap)<k:
                ans.append(-1)
            else:
                while len(heap)>k:
                    heapq.heappop(heap)
                ans.append(-heap[0])
        return ans

class Solution:
    def majorityElement(self, nums: List[int]) -> List[int]:
