class Solution:
    def sumEvenAfterQueries(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        ans = []
        even = sum(i for i in nums if i % 2 == 0)
        for val, index in queries:
            old = nums[index]
            nums[index] = nums[index] + val
            if old % 2 == 0 and nums[index] % 2 == 1:
                even -= old
            elif old % 2 == 0 and nums[index] % 2 == 0:
                even -= old
                even += nums[index]
            elif nums[index] % 2 == 0:
                even += nums[index]
            ans.append(even)
        return ans

