import threading
class FooBar:
    def __init__(self, n):
        self.n = n
        self.t1=threading.Lock()
        self.t2=threading.Lock()
        self.t2.acquire()
    def foo(self, printFoo: 'Callable[]: None'):
        for i in range(self.n):
            self.t1.acquire()
            printFoo()
            self.t2.release()
    def bar(self, printBar: 'Callable[]: None'):
        for i in range(self.n):
            self.t2.acquire()
            printBar()
            self.t1.release()

