/**
 * @param {integer} init
 * @return { increment: Function, decrement: Function, reset: Function }
 */
var createCounter = function(init) {
    const current=init
    return {
        increment: function () {
            init+=1
            return init
        },
        decrement: function () {
            init-=1
            return init
        },
        reset: function() {
            init=current
            return init
        }
    }
};

