 * @return {Array}
 */
var chunk = function(arr, size) {
    let temp=[]
    let ans=[]
    let count=0
    for (let i=0; i<arr.length; i++) {
        count+=1
        temp.push(arr[i])
        if (count===size) {
            ans.push(temp)
            temp=[]
            count=0
        }
    }
    if (temp.length>0) {
        ans.push(temp)
    }
    return ans
};

