/**
 * @param {Function} fn
 */
function memoize(fn) {

   const cache = {};

   return function(...args) {
    const key = JSON.stringify(args);

    if (key in cache) {
      return cache[key];
    }

    const result = fn.apply(this, args);
    cache[key] = result;

    return result;
  }

}


