class Solution:
    def evalRPN(self, tokens: List[str]) -> int:
        stack=[]
        for i in tokens:
            if i in '*-+/':
                x=stack.pop()
                y=stack.pop()
                if i=='+':
                    stack.append(int(y)+int(x))
                elif i=='-':
                    stack.append(int(y)-int(x))
                elif i=='*':
                    stack.append(int(y)*int(x))
                elif i=='/':
                    stack.append(int(y)/int(x))
                else:
                    stack.append(i)
            else:
                stack.append(i)
        return int(stack.pop())

/**
 * @param {number} n
 * @param {string[]} logs
 * @return {number[]}
 */
var exclusiveTime = function(n, logs) {
    const res = new Array(n).fill(0);
    const stack = [];
    let prev = 0;
    for (let i = 0; i < logs.length; i++) {
        const parts = logs[i].split(':');
        const id = parseInt(parts[0]);
        const type = parts[1];
        const t = parseInt(parts[2]);
        if (type === 'start') {
            if (stack.length > 0) {
                res[stack.at(-1)] += t - prev;
            }
            stack.push(id);
            prev = t;
        } else {
            const finished = stack.pop();
            res[finished] += t - prev + 1;
            prev = t + 1;
        }
    }
    return res;
};

