/**
 * @param {number[]} tickets
 * @param {number} k
 * @return {number}
 */
var timeRequiredToBuy = function(tickets, k) {
  let q = [];
  for (let i = 0; i < tickets.length; i++) q.push(i);

  let time = 0;

  while (true) {
    let i = q.shift();     // person at front
    tickets[i]--;          // they buy 1 ticket
    time++;                // 1 second passes

    if (tickets[i] === 0) {
      if (i === k) return time;   // k just finished
      // otherwise they leave (do nothing)
    } else {
      q.push(i);           // still needs tickets, go to back
    }
  }
};

class Solution:
    def lastStoneWeight(self, stones: List[int]) -> int:
        heap=[]
        for i in stones:
            heap.append(-i)
        heapq.heapify(heap)
        while len(heap)>1:
            rock=heapq.heappop(heap)
            rock2=heapq.heappop(heap)
            if rock!=rock2:
                heapq.heappush(heap, abs(rock2)-abs(rock))
        try:
            return abs(heap[0])
        except IndexError:
            return 0

/**
 * @param {number[]} target
 * @return {boolean}
 */
var isPossible = function(target) {

    if (target.length === 1) 
        return target[0] === 1;

    const maxHeap = new MaxPriorityQueue(); 
    let total = 0;

    for (let num of target) {
        maxHeap.enqueue(num);
        total += num;
    }

    while (true) {
        let x = maxHeap.dequeue();
        let rest = total - x;

        if (x === 1 || rest === 1) return true;
        if (rest === 0 || x < rest || x % rest === 0) return false;

        let prev = x % rest;
        total = rest + prev;
        maxHeap.enqueue(prev);
    }

    return false;
};

